import android.content.Context;
import android.content.SharedPreferences;
import android.security.keystore.KeyGenParameterSpec;
import android.security.keystore.KeyProperties;
import androidx.biometric.BiometricManager;
import androidx.biometric.BiometricPrompt;
import androidx.core.content.ContextCompat;
import androidx.fragment.app.FragmentActivity;
import javax.crypto.Cipher;
import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;
import java.security.KeyStore;

public class BiometricAuthManager {
    private static final String PREFS_NAME = "BiometricPrefs";
    private static final String KEY_BIOMETRIC_ENABLED = "biometric_enabled";
    private static final String KEY_USER_AUTHENTICATED = "user_authenticated";
    private static final String KEYSTORE_ALIAS = "BiometricKey";
    private static final String ANDROID_KEYSTORE = "AndroidKeyStore";
    
    private Context context;
    private SharedPreferences sharedPreferences;
    
    public BiometricAuthManager(Context context) {
        this.context = context;
        this.sharedPreferences = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
    }
    
    public boolean isBiometricEnabled() {
        return sharedPreferences.getBoolean(KEY_BIOMETRIC_ENABLED, false);
    }
    
    public void setBiometricEnabled(boolean enabled) {
        sharedPreferences.edit().putBoolean(KEY_BIOMETRIC_ENABLED, enabled).apply();
    }
    
    public boolean isUserAuthenticated() {
        return sharedPreferences.getBoolean(KEY_USER_AUTHENTICATED, false);
    }
    
    public void setUserAuthenticated(boolean authenticated) {
        sharedPreferences.edit().putBoolean(KEY_USER_AUTHENTICATED, authenticated).apply();
    }
    
    public void logout() {
        setUserAuthenticated(false);
    }
    
    public boolean canAuthenticateWithBiometrics() {
        BiometricManager biometricManager = BiometricManager.from(context);
        int canAuthenticate = biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG);
        return canAuthenticate == BiometricManager.BIOMETRIC_SUCCESS;
    }
    
    public String getBiometricStatusMessage() {
        BiometricManager biometricManager = BiometricManager.from(context);
        int canAuthenticate = biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG);
        
        switch (canAuthenticate) {
            case BiometricManager.BIOMETRIC_SUCCESS:
                return "Biometric authentication available";
            case BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE:
                return "No biometric hardware available";
            case BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE:
                return "Biometric hardware unavailable";
            case BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED:
                return "No biometric credentials enrolled";
            default:
                return "Biometric authentication not available";
        }
    }
    
    private SecretKey generateSecretKey() {
        try {
            KeyGenerator keyGenerator = KeyGenerator.getInstance(
                    KeyProperties.KEY_ALGORITHM_AES, ANDROID_KEYSTORE);
            
            KeyGenParameterSpec keyGenParameterSpec = new KeyGenParameterSpec.Builder(
                    KEYSTORE_ALIAS,
                    KeyProperties.PURPOSE_ENCRYPT | KeyProperties.PURPOSE_DECRYPT)
                    .setBlockModes(KeyProperties.BLOCK_MODE_CBC)
                    .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_PKCS7)
                    .setUserAuthenticationRequired(true)
                    .setInvalidatedByBiometricEnrollment(true)
                    .build();
            
            keyGenerator.init(keyGenParameterSpec);
            return keyGenerator.generateKey();
        } catch (Exception e) {
            e.printStackTrace();
            return null;
        }
    }
    
    private SecretKey getSecretKey() {
        try {
            KeyStore keyStore = KeyStore.getInstance(ANDROID_KEYSTORE);
            keyStore.load(null);
            
            if (!keyStore.containsAlias(KEYSTORE_ALIAS)) {
                return generateSecretKey();
            }
            
            return (SecretKey) keyStore.getKey(KEYSTORE_ALIAS, null);
        } catch (Exception e) {
            e.printStackTrace();
            return null;
        }
    }
    
    private Cipher getCipher() {
        try {
            return Cipher.getInstance(KeyProperties.KEY_ALGORITHM_AES + "/"
                    + KeyProperties.BLOCK_MODE_CBC + "/"
                    + KeyProperties.ENCRYPTION_PADDING_PKCS7);
        } catch (Exception e) {
            e.printStackTrace();
            return null;
        }
    }
    
    public void authenticateWithBiometric(FragmentActivity activity, BiometricAuthCallback callback) {
        BiometricPrompt.PromptInfo promptInfo = new BiometricPrompt.PromptInfo.Builder()
                .setTitle("Biometric Authentication")
                .setSubtitle("Unlock with your fingerprint")
                .setNegativeButtonText("Cancel")
                .build();
        
        BiometricPrompt biometricPrompt = new BiometricPrompt(activity,
                ContextCompat.getMainExecutor(context),
                new BiometricPrompt.AuthenticationCallback() {
                    @Override
                    public void onAuthenticationError(int errorCode, CharSequence errString) {
                        super.onAuthenticationError(errorCode, errString);
                        callback.onAuthenticationError(errorCode, errString.toString());
                    }
                    
                    @Override
                    public void onAuthenticationSucceeded(BiometricPrompt.AuthenticationResult result) {
                        super.onAuthenticationSucceeded(result);
                        setUserAuthenticated(true);
                        callback.onAuthenticationSucceeded();
                    }
                    
                    @Override
                    public void onAuthenticationFailed() {
                        super.onAuthenticationFailed();
                        callback.onAuthenticationFailed();
                    }
                });
        
        try {
            Cipher cipher = getCipher();
            SecretKey secretKey = getSecretKey();
            
            if (cipher != null && secretKey != null) {
                cipher.init(Cipher.ENCRYPT_MODE, secretKey);
                BiometricPrompt.CryptoObject cryptoObject = new BiometricPrompt.CryptoObject(cipher);
                biometricPrompt.authenticate(promptInfo, cryptoObject);
            } else {
                biometricPrompt.authenticate(promptInfo);
            }
        } catch (Exception e) {
            e.printStackTrace();
            biometricPrompt.authenticate(promptInfo);
        }
    }
    
    public interface BiometricAuthCallback {
        void onAuthenticationSucceeded();
        void onAuthenticationFailed();
        void onAuthenticationError(int errorCode, String errorMessage);
    }
}

// LoginActivity.java
import android.content.Intent;
import android.os.Bundle;
import android.view.View;
import android.widget.Button;
import android.widget.CheckBox;
import android.widget.EditText;
import android.widget.Toast;
import androidx.appcompat.app.AppCompatActivity;

public class LoginActivity extends AppCompatActivity {
    private EditText etUsername;
    private EditText etPassword;
    private Button btnLogin;
    private CheckBox cbEnableBiometric;
    private BiometricAuthManager biometricAuthManager;
    
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);
        
        biometricAuthManager = new BiometricAuthManager(this);
        
        if (biometricAuthManager.isUserAuthenticated() && biometricAuthManager.isBiometricEnabled()) {
            showBiometricPrompt();
            return;
        }
        
        initializeViews();
        setupListeners();
        setupBiometricCheckbox();
    }
    
    private void initializeViews() {
        etUsername = findViewById(R.id.etUsername);
        etPassword = findViewById(R.id.etPassword);
        btnLogin = findViewById(R.id.btnLogin);
        cbEnableBiometric = findViewById(R.id.cbEnableBiometric);
    }
    
    private void setupListeners() {
        btnLogin.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                performLogin();
            }
        });
    }
    
    private void setupBiometricCheckbox() {
        if (biometricAuthManager.canAuthenticateWithBiometrics()) {
            cbEnableBiometric.setVisibility(View.VISIBLE);
            cbEnableBiometric.setChecked(biometricAuthManager.isBiometricEnabled());
        } else {
            cbEnableBiometric.setVisibility(View.GONE);
            Toast.makeText(this, biometricAuthManager.getBiometricStatusMessage(), Toast.LENGTH_SHORT).show();
        }
    }
    
    private void performLogin() {
        String username = etUsername.getText().toString().trim();
        String password = etPassword.getText().toString().trim();
        
        if (username.isEmpty() || password.isEmpty()) {
            Toast.makeText(this, "Please enter username and password", Toast.LENGTH_SHORT).show();
            return;
        }
        
        if (authenticateUser(username, password)) {
            biometricAuthManager.setUserAuthenticated(true);
            biometricAuthManager.setBiometricEnabled(cbEnableBiometric.isChecked());
            
            navigateToMainActivity();
        } else {
            Toast.makeText(this, "Invalid credentials", Toast.LENGTH_SHORT).show();
        }
    }
    
    private boolean authenticateUser(String username, String password) {
        return username.equals("admin") && password.equals("password");
    }
    
    private void showBiometricPrompt() {
        biometricAuthManager.authenticateWithBiometric(this, new BiometricAuthManager.BiometricAuthCallback() {
            @Override
            public void onAuthenticationSucceeded() {
                Toast.makeText(LoginActivity.this, "Authentication succeeded", Toast.LENGTH_SHORT).show();
                navigateToMainActivity();
            }
            
            @Override
            public void onAuthenticationFailed() {
                Toast.makeText(LoginActivity.this, "Authentication failed", Toast.LENGTH_SHORT).show();
            }
            
            @Override
            public void onAuthenticationError(int errorCode, String errorMessage) {
                Toast.makeText(LoginActivity.this, "Authentication error: " + errorMessage, Toast.LENGTH_SHORT).show();
            }
        });
    }
    
    private void navigateToMainActivity() {
        Intent intent = new Intent(LoginActivity.this, MainActivity.class);
        startActivity(intent);
        finish();
    }
}

// MainActivity.java
import android.content.Intent;
import android.os.Bundle;
import android.view.View;
import android.widget.Button;
import android.widget.TextView;
import androidx.appcompat.app.AppCompatActivity;

public class MainActivity extends AppCompatActivity {
    private TextView tvWelcome;
    private Button btnLogout;
    private BiometricAuthManager biometricAuthManager;
    
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);
        
        biometricAuthManager = new BiometricAuthManager(this);
        
        if (!biometricAuthManager.isUserAuthenticated()) {
            navigateToLogin();
            return;
        }
        
        initializeViews();
        setupListeners();
    }
    
    private void initializeViews() {
        tvWelcome = findViewById(R.id.tvWelcome);
        btnLogout = findViewById(R.id.btnLogout);
        
        String biometricStatus = biometricAuthManager.isBiometricEnabled() ? 
                "Biometric login enabled" : "Biometric login disabled";
        tvWelcome.setText("Welcome!\n" + biometricStatus);
    }
    
    private void setupListeners() {
        btnLogout.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                performLogout();
            }
        });
    }
    
    private void performLogout() {
        biometricAuthManager.logout();
        navigateToLogin();
    }
    
    private void navigateToLogin() {
        Intent intent = new Intent(MainActivity.this, LoginActivity.class);
        startActivity(intent);
        finish();
    }
}